typedef struct {
    int64_t key;
    int count;
    UT_hash_handle hh;
} PairCount;

static inline int64_t make_key(int x1, int x2) {
    int64_t a = (int64_t)(int32_t)x1;
    int64_t b = (int64_t)(uint32_t)x2;
    return (a << 32) | b;
}

int main() {
    int T; 
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int *xs = (int*)malloc(N * sizeof(int));
        int *ys = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) scanf("%d %d", &xs[i], &ys[i]);
        // group by y using simple array of indices (N is small)
        PairCount *hash = NULL;
        for (int i = 0; i < N; ++i) {
            for (int j = i + 1; j < N; ++j) {
                if (ys[i] != ys[j]) continue; // same y needed
                int x1 = xs[i];
                int x2 = xs[j];
                if (x1 == x2) continue; // same x cannot form side
                if (x1 > x2) { int tmp = x1; x1 = x2; x2 = tmp; }
                int64_t key = make_key(x1, x2);
                PairCount *pc;
                HASH_FIND_INT64(hash, &key, pc);
                if (pc) {
                    pc->count++;
                } else {
                    pc = (PairCount*)malloc(sizeof(PairCount));
                    pc->key = key;
                    pc->count = 1;
                    HASH_ADD_INT64(hash, key, pc);
                }
            }
        }
        long long ans = 0;
        PairCount *pc, *tmp;
        for (pc = hash; pc != NULL; ) {
            long long c = pc->count;
            ans += c * (c - 1) / 2;
            tmp = pc;
            pc = (PairCount*)pc->hh.next;
            free(tmp);
        }
        printf("%lld\n", ans);
        free(xs);
        free(ys);
    }
    return 0;
}

