#include <bits/stdc++.h>
using namespace std;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N; cin>>N;
        vector<int> xs(N), ys(N);
        for(int i=0;i<N;++i) cin>>xs[i]>>ys[i];
        unordered_map<long long,int> cnt;
        cnt.reserve(N*N);
        for(int i=0;i<N;++i){
            for(int j=i+1;j<N;++j){
                if(ys[i]!=ys[j]) continue; // same y
                int x1=xs[i], x2=xs[j];
                if(x1==x2) continue;
                if(x1>x2) swap(x1,x2);
                long long key = ( (long long)(int64_t)x1 << 32 ) | (uint32_t)x2;
                ++cnt[key];
            }
        }
        long long ans=0;
        for(auto &p:cnt){
            long long c=p.second;
            ans+=c*(c-1)/2;
        }
        cout<<ans<<"\n";
    }
    return 0;
}
